=Company: {{ $('CV Factory').item.json.query.company }}
jon title : {{ $('CV Factory').item.json.query.job_title }}
job Url: {{ $('CV Factory').item.json.query.job_url }}
Description: {{ $('CV Factory').item.json.query.job_description }}

parameters.jsCode:
// 1. On récupère le texte généré par l'Agent
const text = $json.output || ""; 
const match = text.match(/\{[\s\S]*\}/);

if (match) {
  try {
    // On parse uniquement le bloc JSON trouvé
    const data = JSON.parse(match);

    // Helper pour les tableaux Notion (Multi-select)
    const toSimpleArray = (val) => {
      if (!val) return [];
      const rawItems = Array.isArray(val) ? val : val.toString().split(/[|,\/&]|\band\b/);
      return rawItems.map(i => i.trim()).filter(i => i.length > 1);
    };

    // 2. On reconstruit l'objet propre pour alimenter le nœud "Update Notion"
    return [{
      json: {
        domain: toSimpleArray(data.domain),
        category: toSimpleArray(data.category || data.job_title),
        job_title: data.job_title || "Position inconnue",
        company: data.company || "Entreprise inconnue",
        score: parseInt(data.match_score) || 0,
        status: "To review",
        summary: data.quick_summary || "Analyse terminée",
        analysis_pros: data.analysis_pros || "N/A",
        analysis_cons: data.analysis_cons || "N/A",
        action_plan: data.action_plan || "N/A",
        generated_cv_markdown: data.generated_cv_markdown || "",
        response_date: new Date().toISOString().split('T')
      }
    }];

  } catch (e) {
    return [{ json: { error: "JSON Parsing Error", message: e.message, raw: text.substring(0, 200) } }];
  }
}

return [{ json: { error: "No JSON found in AI output", raw: text.substring(0, 100) } }];

// 1. Récupération des lignes du CV Atomique
let cvRows = [];
try {
  cvRows = $('Get CV data').all();
} catch (e) {
  cvRows = [];
}

// Extraction universelle pour le CV
const cleanExperiences = cvRows.map((row, index) => {
  const props = row.json?.properties || {};

  // Fonction helper pour extraire le texte brut d'une propriété Notion, quel que soit son type (title ou rich_text)
  const extractText = (propObj) => {
    if (!propObj) return "";
    const arr = propObj.rich_text || propObj.title || [];
    return arr?.plain_text || propObj.value || "";
  };

  // On scanne dynamiquement les variantes de noms de colonnes possibles
  const entreprise = extractText(props.Entreprise) || extractText(props.Company) || "Entreprise " + (index + 1);
  const poste = extractText(props.Poste) || extractText(props.Role) || "Solutions Engineer";
  const description = extractText(props.Description) || "";
  const dates = extractText(props.Dates) || extractText(props.Date) || "";

  return `### ${poste} chez ${entreprise} (${dates})\n${description}`;
}).join("\n\n");

// 2. Récupération et isolation de la Graine UNIQUE
let seedBaseline = "Solutions Engineer";
let seedDirectives = "Standard tailoring";

try {
  const allSeeds = $('CV Seed').all();
  // On cherche la graine active via la checkbox, sinon on prend la première disponible
  const selectedSeedItem = allSeeds.find(item => {
    const props = item.json?.properties || {};
    // Gère la checkbox Notion (qu'elle s'appelle Active ou active)
    const checkObj = props.Active || props.active;
    return checkObj?.checkbox === true;
  }) || allSeeds;

  if (selectedSeedItem && selectedSeedItem.json?.properties) {
    const sProps = selectedSeedItem.json.properties;

    const extractSeedText = (propObj) => {
      if (!propObj) return null;
      const arr = propObj.title || propObj.rich_text || [];
      return arr?.plain_text || null;
    };

    seedBaseline = extractSeedText(sProps.Baseline) || extractSeedText(sProps.baseline) || seedBaseline;
    seedDirectives = extractSeedText(sProps.Directives) || extractSeedText(sProps.directives) || seedDirectives;
  }
} catch (e) {
  // En cas de problème de lecture de la graine, on garde les valeurs par défaut pour ne pas bloquer le flux
}

// 3. Payload plat final garanti sans crash
return [{
  json: {
    job_description: $json.job_description || "Pas de description",
    seed_baseline: seedBaseline,
    seed_directives: seedDirectives,
    cv_master_payload: cleanExperiences || "CV Master vide"
  }
}];

